Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string fileName, searchWord;
    int count = 0;

    // Get input from user
    std::cout << "Enter the name of the file: ";
    std::cin >> fileName;
    std::cout << "Enter the word to search: ";
    std::cin >> searchWord;

    // Open the file
    std::ifstream file(fileName);
    if (!file.is_open()) {
        std::cerr << "Error opening file." << std::endl;
        return 1;
    }

    std::string line;
    while (std::getline(file, line)) {
        // Convert the line to lowercase for case-insensitive search
        std::transform(line.begin(), line.end(), line.begin(), ::tolower);

        // Count the occurrences of the search word in the line
        size_t pos = 0;
        while ((pos = line.find(searchWord, pos)) != std::string::npos) {
            count++;
            pos += searchWord.length();
        }
    }

    file.close();
    std::cout << "The word '" << searchWord << "' appears " << count << " times in the file." << std::endl;

    return 0;
}
```

